namespace sv_aeb4837d8201498c9c349fd6605f2b7e.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeService
{
    public Theme CurrentTheme { get; private set; } = Theme.Light;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public void SetTheme(Theme theme)
    {
        if (CurrentTheme == theme) return;
        CurrentTheme = theme;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    public void SetPreferences(Theme theme, string accentColor)
    {
        var changed = CurrentTheme != theme || AccentColor != accentColor;
        CurrentTheme = theme;
        AccentColor = accentColor;
        if (changed) OnChange?.Invoke();
    }
}

@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator" title="Current theme: @ThemeService.CurrentTheme">
    @GetThemeIcon() @ThemeService.CurrentTheme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private string GetThemeIcon() => ThemeService.CurrentTheme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Current: @ThemeService.CurrentTheme — click to change">
