</button>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private void CycleTheme()
    {
        var next = ThemeService.CurrentTheme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        ThemeService.SetTheme(next);
    }

    private string GetThemeIcon() => ThemeService.CurrentTheme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Appearance</h5>

        <div class="mb-3">
            <label class="form-label">Theme</label>
            <select class="form-select" value="@ThemeService.CurrentTheme"
                    @onchange="OnThemeChanged">
                @foreach (var theme in Enum.GetValues<Theme>())
                {
                    <option value="@theme">@theme</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeService.AccentColor"
                       @onchange="OnAccentColorChanged" />
                <span class="text-muted">@ThemeService.AccentColor</span>
            </div>
        </div>

        <div class="alert alert-info mt-3 mb-0">
            <strong>Current:</strong> @ThemeService.CurrentTheme theme,
            accent <span style="color: @ThemeService.AccentColor;">■</span>
            @ThemeService.AccentColor
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            ThemeService.SetTheme(theme);
        }
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrEmpty(color))
        {
            ThemeService.SetAccentColor(color);
        }
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

