            accent <span style="color: @ThemeService.AccentColor;">■</span>
            @ThemeService.AccentColor
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private void OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            ThemeService.SetTheme(theme);
        }
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrEmpty(color))
        {
            ThemeService.SetAccentColor(color);
        }
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

