public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeService
{
    public Theme CurrentTheme { get; private set; } = Theme.Light;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public void SetTheme(Theme theme)
    {
        if (CurrentTheme == theme) return;
        CurrentTheme = theme;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    public void SetPreferences(Theme theme, string accentColor)
    {
        var changed = CurrentTheme != theme || AccentColor != accentColor;
        CurrentTheme = theme;
        AccentColor = accentColor;
        if (changed) OnChange?.Invoke();
    }
}

